void intr_on()
{
    S_CSR(sstatus, SSTATUS_SIE);
}

void intr_off()
{
    C_CSR(sstatus, SSTATUS_SIE);
}

void intr_pop(){
    uint64 push_off_num = --get_cpu()->push_off_num;
    if (push_off_num == 0)
    {
        if (get_cpu()->intr_status != 0)
            intr_on();
    }
}

void intr_push(){
    if (get_cpu()->push_off_num++ == 0){
        uint64 sstatus;
        R_CSR(sstatus, sstatus);
        if (sstatus & SSTATUS_SIE)
        {
            get_cpu()->intr_status = 1;
            intr_off();
        }
        else
            get_cpu()->intr_status = 0;
    }
}

int dev_intr()
{
    uint64 scause;
    R_CSR(scause, scause);
    //printf("dev_intr: enter devintr 0x%p\n", scause);
    if ((scause & INTR_HEAD) &&
        (scause & 0xff) == 9)
    {
        // this is a supervisor external interrupt, via PLIC.

        // irq indicates which device interrupted.
        int irq = plic_claim();

        if (irq == UART0_IRQ)
        {
            //printf("dev_intr: uart intr!!!!!!!!!!!!!!\n");
            //TODO: uart_intr();
        }
        else if (irq == VIRTIO0_IRQ)
        {
            //printf("dev_intr: virtio intr!!!!!!!!!!!!!!\n");
            virtio_disk_intr();
            //printf("dev_intr: finish virtio disk intr\n");
        }
        else if (irq)
        {
            printf("unexpected interrupt irq=%d\n", irq);
        }

        // the PLIC allows each device to raise at most one
        // interrupt at a time; tell the PLIC the device is
        // now allowed to interrupt again.
        if (irq)
        {
            plic_complete(irq);
            //printf("dev_intr: complete irq\n");
        }

        return 1;
    }
    else if (scause == (0x8000000000000001))
    {
        // software interrupt from a machine-mode timer interrupt,
        // forwarded by timervec in kernelvec.S.

        if (get_cpu_id() == 0)
        {
            //TODO: clock_intr();
        }
        // acknowledge the software interrupt by clearing
        // the SSIP bit in sip.
        uint64 sip;
        R_CSR(sip,sip);
        W_CSR(sip, sip & ~2);
        return 2;
    }
    else
    {
        return 0;
    }
}

void intr_print() {
