void usertrap()
{

    int tid = get_tid();
    uint64 scause = 0, sepc = 0;
    int which_dev;

    intr_push();


    set_strap_stvec();

    R_CSR(scause, scause);
    R_CSR(sepc, sepc);

    thread_pool[tid].trapframe->epc = sepc;
    LOG("User trap\n scause = %p, sepc = %p\n", scause, sepc);
    assert(get_cpu()->push_off_num == 2);
    switch (scause)
    {
    case SCAUSE_ECALL:
        resolve_ecall();
        goto return_to_user;
        break;

    case SCAUSE_LOAD_PAGE_FAULT:
    case SCAUSE_STORE_AMO_PAGE_FAULT:
        if (resolve_page_fault()) {
            goto return_to_user;
        } else {
            sys_exit(-1);
            goto switch_to;
        }
        break;

    default:
        if((which_dev = dev_intr()) == 0) {
            resolve_unknown_trap();
            // thread_pool[tid].state = T_SLEEPING;
            goto switch_to;
        } else {
            thread_pool[tid].state = T_READY;
            goto switch_to;
        }
        break;
    }

return_to_user:
    intr_pop();
    entry_to_user();
switch_to:
    sched();
    intr_pop();
    entry_to_user();
}

