  W_UART_REG(1, 0x00);

  // leave set-baud mode,
  // and set word length to 8 bits, no parity.
  W_UART_REG(LCR, LCR_EIGHT_BITS);

  // reset and enable FIFOs.
  W_UART_REG(FCR, FCR_FIFO_ENABLE | FCR_FIFO_CLEAR);

  // enable transmit and receive interrupts.
  //TODO: open this
